def z_algorithm(text, pattern):
    if not pattern:
        return list(range(len(text) + 1))
    if not text:
        return []

    separator = "$"
    s = pattern + separator + text
    n = len(s)
    m = len(pattern)

    z = [0] * n
    l, r = 0, 0

    for i in range(1, n):
        if i <= r:
            k = i - l
            z[i] = min(r - i + 1, z[k])

        while i + z[i] < n and s[z[i]] == s[i + z[i]]:
            z[i] += 1

        if i + z[i] - 1 > r:
            l = i
            r = i + z[i] - 1

    occurrences = []
    for i in range(n):
        if z[i] == m:
            if i >= m + len(separator):
                occurrences.append(i - m - len(separator))

    return occurrences
